const parsedText = ($json.ParsedResults?.[0]?.ParsedText || '').trim();

let trigger = {};
try {
  trigger = $('Google Drive Trigger').first().json;
} catch (e) {
  trigger = $input.item.json || {};
}

return {
  json: {
    ocr_text: parsedText,
    source_file_id: trigger.id || null,
    source_file_name: trigger.name || null,
    source_file_mime_type: trigger.mimeType || null,
    source_file_created_time: trigger.createdTime || null,
    source_file_link: trigger.webViewLink || null
  }
};

const raw = $json.choices?.[0]?.message?.content || '';

const rawContent = raw
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

let parsed = {};
let parseError = null;

if (rawContent) {
  try {
    parsed = JSON.parse(rawContent);
  } catch (error) {
    parseError = `Invalid JSON from AI: ${error.message}`;
  }
} else {
  parseError = 'Empty AI response';
}

let normalizeData = {};
try {
  normalizeData = $('Normalize OCR Text1').first().json || {};
} catch (e) {
  try {
    normalizeData = $('Normalize OCR Text').first().json || {};
  } catch {
    normalizeData = {};
  }
}

const ocrText = String(normalizeData.ocr_text || '');

function cleanText(value) {
  if (value === null || value === undefined) return null;
  const v = String(value).trim();
  return v === '' ? null : v;
}

function toNumber(value) {
  if (value === null || value === undefined || value === '') return null;
  const cleaned = String(value).replace(/[^0-9.-]/g, '');
  const num = Number(cleaned);
  return Number.isNaN(num) ? null : num;
}

function pickFirst(...values) {
  for (const value of values) {
    const cleaned = cleanText(value);
    if (cleaned) return cleaned;
  }
  return null;
}

function extractByRegex(text, regex) {
  const match = text.match(regex);
  return match?.[1] ? match[1].trim() : null;
}

function normalizeDate(value) {
  if (!value) return null;
  const v = String(value).trim();

  // keep original if already ISO
  if (/^\d{4}-\d{2}-\d{2}$/.test(v)) return v;

  // dd/mm/yyyy or mm/dd/yyyy style
  const slashMatch = v.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (slashMatch) {
    // assume OCR invoice format as written, keep exact text
    return v;
  }

  const d = new Date(v);
  if (!Number.isNaN(d.getTime())) {
    return d.toISOString().split('T')[0];
  }

  return v;
}

function inferDueDate(rawText, invoiceDate, currentDueDate) {
  if (currentDueDate) return currentDueDate;
  if (!invoiceDate) return null;

  const netMatch = String(rawText || '').match(/net\s*(\d{1,3})/i);
  if (!netMatch) return null;

  const days = Number(netMatch[1]);
  if (Number.isNaN(days)) return null;

  // try parsing known formats
  let base = null;

  if (/^\d{2}\/\d{2}\/\d{4}$/.test(invoiceDate)) {
    const [a, b, y] = invoiceDate.split('/').map(Number);
    // assume mm/dd/yyyy for billing docs like your Microsoft sample
    base = new Date(y, a - 1, b);
  } else {
    base = new Date(invoiceDate);
  }

  if (!base || Number.isNaN(base.getTime())) return null;

  base.setDate(base.getDate() + days);
  return base.toISOString().split('T')[0];
}

// ---------- OCR fallbacks ----------
const fallbackVendor =
  extractByRegex(ocrText, /^([^\n]+?(?:Ltd|LLC|Inc|Corporation|Corp|Pte Ltd|Limited))/im) ||
  extractByRegex(ocrText, /^([^\n]+?Regional Sales[^\n]*)/im);

const fallbackInvoiceNumber =
  extractByRegex(ocrText, /Invoice\s*Number[:\s]+([A-Z0-9-]+)/i) ||
  extractByRegex(ocrText, /Invoice\s*No\.?[:\s]+([A-Z0-9-]+)/i) ||
  extractByRegex(ocrText, /Document\s*Number[:\s]+([A-Z0-9-]+)/i);

const fallbackInvoiceDate =
  extractByRegex(ocrText, /Invoice\s*Date[:\s]+([0-9\/-]+)/i) ||
  extractByRegex(ocrText, /Document\s*Date[:\s]+([0-9\/-]+)/i);

const fallbackDueDate =
  extractByRegex(ocrText, /Due\s*Date[:\s]+([0-9\/-]+)/i) ||
  extractByRegex(ocrText, /Due\s*on[:\s]+([0-9\/-]+)/i) ||
  extractByRegex(ocrText, /Payment\s*Due[:\s]+([0-9\/-]+)/i) ||
  extractByRegex(ocrText, /\bDue[:\s]+([0-9\/-]+)/i);

const fallbackCurrency =
  extractByRegex(ocrText, /Total(?:\s*\(including Tax\))?\s+(USD|PHP|EUR|SGD|GBP|AUD|JPY|CAD)\s+[0-9.,-]+/i) ||
  extractByRegex(ocrText, /Total\s+(USD|PHP|EUR|SGD|GBP|AUD|JPY|CAD)\s+[0-9.,-]+/i);

const fallbackSubtotal =
  extractByRegex(ocrText, /Subtotal[:\s]+([0-9.,-]+)/i) ||
  extractByRegex(ocrText, /Total\s*\(excluding Tax\)[:\s]+([0-9.,-]+)/i);

const fallbackTax =
  extractByRegex(ocrText, /Tax(?:\s*Amount)?[:\s]+([0-9.,-]+)/i) ||
  extractByRegex(ocrText, /VAT(?:\s*[0-9.%]+)?[:\s]+([0-9.,-]+)/i);

const fallbackTotal =
  extractByRegex(ocrText, /Total\s*\(including Tax\)\s+(?:USD|PHP|EUR|SGD|GBP|AUD|JPY|CAD)?\s*([0-9.,-]+)/i) ||
  extractByRegex(ocrText, /Total\s+(?:USD|PHP|EUR|SGD|GBP|AUD|JPY|CAD)\s+([0-9.,-]+)/i) ||
  extractByRegex(ocrText, /Amount\s*Due[:\s]+(?:USD|PHP|EUR|SGD|GBP|AUD|JPY|CAD)?\s*([0-9.,-]+)/i) ||
  extractByRegex(ocrText, /Total\s*Amount[:\s]+(?:USD|PHP|EUR|SGD|GBP|AUD|JPY|CAD)?\s*([0-9.,-]+)/i);

// ---------- final values ----------
const vendorName = pickFirst(parsed.vendor_name, fallbackVendor);
const invoiceNumber = pickFirst(parsed.invoice_number, fallbackInvoiceNumber);
const invoiceDate = normalizeDate(pickFirst(parsed.invoice_date, fallbackInvoiceDate));
const dueDate = normalizeDate(
  inferDueDate(
    ocrText,
    invoiceDate,
    pickFirst(parsed.due_date, fallbackDueDate)
  )
);
const currency = pickFirst(parsed.currency, fallbackCurrency);
const subtotal = toNumber(pickFirst(parsed.subtotal, fallbackSubtotal));
const tax = toNumber(pickFirst(parsed.tax, fallbackTax));
const totalAmount = toNumber(pickFirst(parsed.total_amount, fallbackTotal));
const suggestedCategory = pickFirst(parsed.suggested_category, 'Other');
const confidenceNotes = cleanText(parsed.confidence_notes);

// ---------- validation ----------
const criticalErrors = [];
const warnings = [];

if (parseError) warnings.push(parseError);

// required critical fields
if (!vendorName) criticalErrors.push('Missing vendor_name');
if (!invoiceNumber) criticalErrors.push('Missing invoice_number');
if (totalAmount === null || Number.isNaN(totalAmount) || totalAmount <= 0) {
  criticalErrors.push('Invalid total_amount');
}

// date warnings, not critical
if (!invoiceDate) warnings.push('Missing invoice_date');
if (!dueDate) warnings.push('Missing due_date');

// date consistency warning
if (invoiceDate && dueDate) {
  let inv = null;
  let due = null;

  if (/^\d{2}\/\d{2}\/\d{4}$/.test(invoiceDate)) {
    const [m, d, y] = invoiceDate.split('/').map(Number);
    inv = new Date(y, m - 1, d);
  } else {
    inv = new Date(invoiceDate);
  }

  if (/^\d{2}\/\d{2}\/\d{4}$/.test(dueDate)) {
    const [m, d, y] = dueDate.split('/').map(Number);
    due = new Date(y, m - 1, d);
  } else {
    due = new Date(dueDate);
  }

  if (!Number.isNaN(inv?.getTime()) && !Number.isNaN(due?.getTime()) && due < inv) {
    warnings.push('due_date is earlier than invoice_date');
  }
}

// numeric consistency warning
if (subtotal !== null && tax !== null && totalAmount !== null) {
  const expected = subtotal + tax;
  const diff = Math.abs(expected - totalAmount);
  if (diff > 0.05) {
    warnings.push(`Total mismatch: subtotal + tax = ${expected.toFixed(2)}, total_amount = ${totalAmount.toFixed(2)}`);
  }
}

// OCR quality warning
if (ocrText.length < 50) {
  warnings.push('OCR text too short');
}

// confidence warning
const confidenceText = String(confidenceNotes || '').toLowerCase();
const lowConfidence = /uncertain|low confidence|missing|unclear|not found/.test(confidenceText);
if (lowConfidence) {
  warnings.push('Low confidence indicated by confidence_notes');
}

// success/fail rule
const isValid = criticalErrors.length === 0;

const output = {
  source_file_name: normalizeData.source_file_name || null,
  source_file_link: normalizeData.source_file_link || null,
  source_file_created_time: normalizeData.source_file_created_time || null,
  ocr_text: ocrText || null,
  openai_raw_content: rawContent,
  vendor_name: vendorName,
  invoice_number: invoiceNumber,
  invoice_date: invoiceDate,
  due_date: dueDate,
  currency: currency,
  subtotal: subtotal,
  tax: tax,
  total_amount: totalAmount,
  suggested_category: suggestedCategory,
  confidence_notes: confidenceNotes,
  status: isValid ? 'Ready for review' : 'Manual Review',
  review_needed: isValid ? 'No' : 'Yes',
  validation_errors: [...criticalErrors, ...warnings].join('; '),
  is_valid: isValid,
  upload_timestamp: new Date().toISOString()
};

return [{ json: output }];

